#!/usr/bin/env node
/**
 * CLI entry wrapper — loads compiled dist/cli/index.js and dispatches to Commander.
 * dist/ is generated by `npm run build` (also run via `npm install` / `npm prepare`).
 *
 * Never edit this file directly; edit src/cli/index.ts then run `npm run build`.
 */
import { fileURLToPath } from 'url';
import { pathToFileURL } from 'url';
import { dirname, resolve } from 'path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const { program } = await import(pathToFileURL(resolve(__dirname, '..', 'dist', 'cli', 'index.js')));
program.parse();
